const express = require('express');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const app = express();

app.use(express.json());

// Rate limiting for level completion
const completionLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many level completions, please try again later'
});

// In-memory storage for game state (use Redis in production)
const gameState = new Map();
const completedLevels = new Map();

// Secure random token generation
function generateSecureToken() {
  return crypto.randomBytes(32).toString('hex');
}

// Validate level completion data
function validateLevelData(data) {
  if (!data.levelId || typeof data.levelId !== 'string') return false;
  if (typeof data.score !== 'number' || data.score < 0) return false;
  if (typeof data.time !== 'number' || data.time < 0) return false;
  if (data.time > 300) return false; // 5 minute max time
  return true;
}

// Reward calculation based on score and time
function calculateRewards(score, time) {
  const baseReward = Math.floor(score / 100);
  const timeBonus = Math.max(0, 100 - Math.floor(time / 2));
  const totalReward = baseReward + timeBonus;
  
  // Randomize reward slightly to prevent pattern detection
  const variance = Math.floor(Math.random() * 10) - 5;
  return Math.max(0, totalReward + variance);
}

// Anti-bot measures
const antiBotTokens = new Map();
const MAX_TOKENS_PER_IP = 5;

// Middleware to check bot detection
app.use((req, res, next) => {
  const ip = req.ip || req.connection.remoteAddress;
  const token = req.headers['x-game-token'];
  
  if (token && antiBotTokens.has(token)) {
    const tokenData = antiBotTokens.get(token);
    if (tokenData.ip === ip && Date.now() - tokenData.timestamp < 300000) {
      // Token is valid and recent
      next();
      return;
    }
  }
  
  // Generate new token for legitimate requests
  const newToken = generateSecureToken();
  antiBotTokens.set(newToken, { ip, timestamp: Date.now() });
  
  // Clean up old tokens
  for (const [key, value] of antiBotTokens.entries()) {
    if (Date.now() - value.timestamp > 300000) {
      antiBotTokens.delete(key);
    }
  }
  
  res.setHeader('X-Game-Token', newToken);
  next();
});

// Endpoint to complete level
app.post('/level-complete', completionLimiter, (req, res) => {
  try {
    const { levelId, score, time } = req.body;
    
    // Validate input
    if (!validateLevelData(req.body)) {
      return res.status(400).json({ 
        error: 'Invalid level data provided' 
      });
    }
    
    const ip = req.ip || req.connection.remoteAddress;
    const userId = `${ip}_${levelId}`;
    
    // Check if level already completed
    if (completedLevels.has(userId)) {
      return res.status(400).json({ 
        error: 'Level already completed' 
      });
    }
    
    // Calculate rewards
    const rewards = calculateRewards(score, time);
    
    // Store completion
    completedLevels.set(userId, {
      levelId,
      score,
      time,
      rewards,
      timestamp: Date.now()
    });
    
    // Update game state
    if (!gameState.has(userId)) {
      gameState.set(userId, { totalScore: 0, totalRewards: 0 });
    }
    
    const userState = gameState.get(userId);
    userState.totalScore += score;
    userState.totalRewards += rewards;
    
    res.json({
      success: true,
      levelId,
      rewards,
      totalRewards: userState.totalRewards,
      message: 'Level completed successfully'
    });
    
  } catch (error) {
    console.error('Level completion error:', error);
    res.status(500).json({ 
      error: 'Internal server error' 
    });
  }
});

// Endpoint to claim rewards
app.post('/claim-rewards', (req, res) => {
  try {
    const ip = req.ip || req.connection.remoteAddress;
    const userId = `${ip}_rewards`;
    
    if (!gameState.has(userId)) {
      return res.status(400).json({ 
        error: 'No rewards to claim' 
      });
    }
    
    const userState = gameState.get(userId);
    const rewards = userState.totalRewards;
    
    // Reset rewards after claiming
    userState.totalRewards = 0;
    
    res.json({
      success: true,
      rewards,
      message: 'Rewards claimed successfully'
    });
    
  } catch (error) {
    console.error('Reward claim error:', error);
    res.status(500).json({ 
      error: 'Internal server error' 
    });
  }
});

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'OK', timestamp: Date.now() });
});

module.exports = app;